require "util.SkillUtil"

GameSkill = class()

function GameSkill:ctor(config, player)
    self.itemId = config.itemId
    self.title = config.title
    self.hint = config.hint
    self.player = player
    self:doAction()
end

function GameSkill:doAction()
    if self.itemId == 2287
            or self.itemId == 2288
            or self.itemId == 2289
            or self.itemId == 2290
            or self.itemId == 2291
            or self.itemId == 2292
            or self.itemId == 2293
            or self.itemId == 2294 then
        SkillUtil:readBook(self.player, self.hint, self.title)
        self.player:checkBookInfo(self.itemId)
    end

    if CustomItemConfig:isCustomItem(self.itemId) then
        HostApi.log("useChristmasBoxItem " .. tostring(self.player.userId))
        SkillUtil:useChristmasBoxItem(self.player, self.itemId)
    end

    self:onRemove()
end

function GameSkill:onRemove()
    self = {}
end



return GameSkill